import javax.jws.WebService;
import javax.jws.soap.SOAPBinding;
import javax.xml.ws.Endpoint;

@WebService(name = "OrderProcessor", targetNamespace = "http://orderprocessor.com")
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT)
public class OrderProcessorImpl {

    public String processOrder(Order order) {
        double totalPrice = 0.0;
        
        for (Item item : order.getItems()) {
            totalPrice += item.getPrice() * item.getQuantity();
        }
        
        return "Order processed successfully with total price: " + totalPrice;
    }

    public static void main(String[] args) {
        Endpoint.publish("http://localhost:8080/OrderProcessor", new OrderProcessorImpl());
    }
}

